using sv_58c8c3ea575746d98457512250c3cd04.Models;

namespace sv_58c8c3ea575746d98457512250c3cd04.Services;

/// <summary>
/// Scoped service holding the current warehouse selection for a single circuit.
/// Components subscribe to <see cref="OnChange"/> to react when the warehouse changes.
/// </summary>
public class WarehouseState
{
    public static readonly IReadOnlyList<Warehouse> AvailableWarehouses =
    [
        new("wh-1", "Warehouse A – East"),
        new("wh-2", "Warehouse B – West"),
        new("wh-3", "Warehouse C – Central"),
    ];

    private Warehouse _current = AvailableWarehouses[0];

    public Warehouse Current => _current;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        var match = AvailableWarehouses.FirstOrDefault(w => w.Id == warehouseId);
        if (match is not null && match != _current)
        {
            _current = match;
            OnChange?.Invoke();
        }
    }
}

namespace sv_58c8c3ea575746d98457512250c3cd04.Services;

/// <summary>
/// Simulates a database query that returns the number of low-stock items for a warehouse.
/// </summary>
public class InventoryAlertService
{
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        var count = Random.Shared.Next(0, 16);
        return Task.FromResult(count);
    }
}

namespace sv_58c8c3ea575746d98457512250c3cd04.Services;

/// <summary>
/// Scoped service that holds the current low-stock alert count and provides polling.
/// Any component can subscribe to <see cref="OnChange"/> to update when new data arrives.
/// Polling is ref-counted: multiple callers can start/stop, and the timer runs
/// as long as at least one caller is active.
/// </summary>
public class AlertState : IDisposable
{
    private readonly InventoryAlertService _alertService;
    private readonly WarehouseState _warehouseState;

    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private int _pollingRefCount;
    private SynchronizationContext? _syncContext;

    public int LowStockCount { get; private set; }

    public event Action? OnChange;

    public AlertState(InventoryAlertService alertService, WarehouseState warehouseState)
    {
        _alertService = alertService;
        _warehouseState = warehouseState;
        _warehouseState.OnChange += OnWarehouseChanged;
    }

    /// <summary>
    /// Begin polling. Safe to call multiple times; polling runs while ref count > 0.
    /// </summary>
    public void StartPolling(SynchronizationContext syncContext)
    {
        _syncContext = syncContext;
        _pollingRefCount++;
        if (_pollingRefCount == 1)
        {
            _cts = new CancellationTokenSource();
            _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
            _ = PollLoopAsync(_cts.Token);
        }
    }

    /// <summary>
    /// Decrement polling ref count. Stops polling when it reaches zero.
    /// </summary>
    public void StopPolling()
    {
        _pollingRefCount = Math.Max(0, _pollingRefCount - 1);
        if (_pollingRefCount == 0)
        {
            CancelPolling();
        }
    }

    /// <summary>
    /// Fetch the latest count immediately (e.g. on warehouse change or first load).
    /// </summary>
    public async Task RefreshAsync()
    {
        LowStockCount = await _alertService.GetLowStockCountAsync(_warehouseState.Current.Id);
        NotifyChanged();
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        try
        {
            // Fetch immediately on start
            await RefreshAsync();

            while (await _timer!.WaitForNextTickAsync(ct))
            {
                LowStockCount = await _alertService.GetLowStockCountAsync(_warehouseState.Current.Id);
                NotifyChanged();
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on stop
        }
    }

    private void OnWarehouseChanged()
    {
        // When the warehouse changes, refresh immediately if polling is active
        if (_pollingRefCount > 0)
        {
            _ = RefreshAsync();
        }
    }

    private void NotifyChanged()
    {
        // OnChange handlers call StateHasChanged, which must run on the sync context.
        // Post to the captured SynchronizationContext so it works from background threads.
        if (_syncContext is not null)
        {
            _syncContext.Post(_ => OnChange?.Invoke(), null);
        }
        else
        {
            OnChange?.Invoke();
        }
    }

    private void CancelPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    public void Dispose()
    {
        _warehouseState.OnChange -= OnWarehouseChanged;
        CancelPolling();
    }
}

