@rendermode InteractiveServer
@inject WarehouseState WarehouseState
@implements IDisposable

<div class="warehouse-selector d-flex align-items-center gap-2">
    <label for="warehouseSelect" class="text-nowrap fw-semibold">📦 Warehouse:</label>
    <select id="warehouseSelect"
            class="form-select form-select-sm"
            value="@WarehouseState.Current.Id"
            @onchange="OnWarehouseChanged">
        @foreach (var wh in Services.WarehouseState.AvailableWarehouses)
        {
            <option value="@wh.Id">@wh.Name</option>
        }
    </select>
</div>

@code {
    protected override void OnInitialized()
    {
        WarehouseState.OnChange += OnStateChanged;
    }

    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        WarehouseState.SetWarehouse(e.Value?.ToString() ?? "");
    }

    private void OnStateChanged() => InvokeAsync(StateHasChanged);

    public void Dispose()
    {
        WarehouseState.OnChange -= OnStateChanged;
    }
}

@rendermode InteractiveServer
@inject AlertState AlertState
@implements IDisposable

<span class="alert-badge position-relative">
    @if (AlertState.LowStockCount > 0)
    {
        <span class="badge bg-danger rounded-pill">@AlertState.LowStockCount</span>
    }
    else
    {
        <span class="badge bg-success rounded-pill">0</span>
    }
</span>

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        AlertState.OnChange += _handler;
    }

    public void Dispose()
    {
        if (_handler is not null)
        {
            AlertState.OnChange -= _handler;
        }
    }
}

@page "/dashboard"
@rendermode InteractiveServer
@inject WarehouseState WarehouseState
@inject AlertState AlertState
@implements IDisposable

<PageTitle>Dashboard – @WarehouseState.Current.Name</PageTitle>

<h1>📊 Warehouse Dashboard</h1>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">Current Warehouse</h5>
        <p class="card-text fs-5">@WarehouseState.Current.Name</p>
    </div>
</div>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">⚠️ Low-Stock Alerts</h5>
        @if (AlertState.LowStockCount > 0)
        {
            <p class="card-text text-danger fs-4 fw-bold">
                @AlertState.LowStockCount items below minimum levels
            </p>
        }
        else
        {
            <p class="card-text text-success fs-4">All stock levels healthy</p>
        }
        <small class="text-muted">Refreshes every 10 seconds</small>
    </div>
</div>

@code {
    private Action? _warehouseHandler;
    private Action? _alertHandler;

    protected override void OnInitialized()
    {
        _warehouseHandler = () => InvokeAsync(StateHasChanged);
        _alertHandler = () => InvokeAsync(StateHasChanged);

        WarehouseState.OnChange += _warehouseHandler;
        AlertState.OnChange += _alertHandler;

        // Start polling; this also fetches the first count immediately
        AlertState.StartPolling(SynchronizationContext.Current!);
