using sv_58c8c3ea575746d98457512250c3cd04.Components;
using sv_58c8c3ea575746d98457512250c3cd04.Services;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents()
    .AddInteractiveServerComponents();

// Scoped = per circuit, so each user gets independent warehouse state and alert counts
builder.Services.AddScoped<WarehouseState>();
builder.Services.AddScoped<InventoryAlertService>();
builder.Services.AddScoped<AlertState>();

